const https = require('https'); //HTTPS module (same as http) for providing an HTTPS interface on top of an HTTP service in order to manage incoming requests using webSockets or any other method provided by socket IPC, SSLSocketServer & TLS Servers. For example the server will be able send/recv data from clients and it must support all cipher suites listed here https://www.ssl.comodo.org
const url = require('url');  // URL module (same as http) for parsing urls in a way that can work with both local file system paths or remote servers to fetch content, parse query strings and fragments etc using the same methods it uses on top of HTTP/HTTPS which are provided by https.
const assert = require('assert'); // Assert module (inbuilt) for error handling purposes providing functions such as isNull(value), equal(actual, expected[, message]) to check if a value fulfills some conditions and throws an exception otherwise in case of failure that it should be able do so easily.
const net = require('net'); //Network module (inbuilt) for creating servers & clients over TCP or IPC using streams ('https') used by https 'module' which provides methods to create a secure server with SSL/TLS, providing encrypted communication between connected peers in the network and also handling all cipher suites supported.
const str = require('string'); // String module for various string operations such as capitalization (title case), camel casing etc  using Node's standard library modules of methods to split a source into an array(of substrings) or concatenate arrays/strings, and convert strings in any format we are going over here it is being used by https 'module'.
const crypto = require('crypto'); // Crypto module for generating random numbers (using the RNG), creating keys & IVs etc.  using Node's standard library modules of methods to generate a secure session key and Iv, or encipher data with SSL/TLS protocol in real time if it is supported by server provided we are going over here
const tls = require('tls'); // TLSServer (same as https) for providing an HTTPS interface on top of HTTP service. Using the same methods and provide secure encrypted communication between connected peers using SSL/certificates or webSockets etc if supported by server provided we are going over here
